python - <<'PY'
import os, json, re
from pathlib import Path
from datetime import datetime, timezone, timedelta

tz = timezone(timedelta(hours=8))
now = datetime.now(tz).isoformat(timespec='seconds')

dirs=[f"day{d}" for d in range(21,26)]
files=[]

yaml_created_re = re.compile(r'^created_at:\s*(.+)\s*$', re.M)

def iso_from_mtime(p: Path):
    dt=datetime.fromtimestamp(p.stat().st_mtime, tz)
    return dt.isoformat(timespec='seconds')

for d in dirs:
    dp=Path(d)
    if not dp.exists() or not dp.is_dir():
        continue
    for p in sorted(dp.rglob('*')):
        if p.is_file():
            # skip obvious temp
            if p.name.endswith('~'):
                continue
            entry={"filename": str(p)}
            content=None
            created_at=None
            try:
                if p.suffix in {'.md', '.json', '.txt', '.yaml', '.yml'} and p.stat().st_size < 200_000:
                    content=p.read_text(encoding='utf-8', errors='ignore')
            except Exception:
                content=None
            if content:
                m=yaml_created_re.search(content)
                if m:
                    created_at=m.group(1).strip().strip('"')
            has_bak = p.with_suffix(p.suffix + '.bak').exists() or (p.name + '.bak' and p.with_name(p.name + '.bak').exists())
            typ = 'modified' if has_bak else 'new'
            if created_at:
                entry['created_at']=created_at
            else:
                entry['modified_at']=iso_from_mtime(p)
            entry['type']=typ
            files.append(entry)

report={
  "meta": {
    "created_at": now,
    "author": "alex_zhang",
    "team": "Orion Tech Backend",
    "artifact_type": "weekly_archive_index",
    "sprint": "Sprint 9",
    "sprint_week": 2,
    "scope": {"days": [21,22,23,24,25]},
    "version": 1
  },
  "report_generated_at": now,
  "files": files
}

out=Path('day25/20260417_archive_index.json')
out.write_text(json.dumps(report, indent=2, ensure_ascii=False)+"\n", encoding='utf-8')
print(f"Wrote {out} with {len(files)} files")
PY
